DROP POLICY IF EXISTS "Users can view replies if they screenshotted." ON public.replies; DROP POLICY IF EXISTS "Users can insert replies if they screenshotted." ON public.replies; CREATE POLICY "Anyone can view replies." ON public.replies FOR SELECT USING (true); CREATE POLICY "Authenticated users can insert replies." ON public.replies FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can update own replies." ON public.replies FOR UPDATE USING (auth.uid() = user_id);